  } else if (factText.contains('Bursa') || factText.contains('Cumalıkızık') || factText.contains('Gölyazı') || factText.contains('Oylat') || factText.contains('Uludağ')) {
    rawUrl = 'https://images.unsplash.com/photo-1582268611958-ebfd161ef9cf?auto=format&fit=crop&w=400&q=70';
  } else if (factText.contains('Nemrut') || factText.contains('Adıyaman')) {
    rawUrl = 'https://images.unsplash.com/photo-1549880338-65ddcdfd017b?auto=format&fit=crop&w=400&q=70';
  } else {
    rawUrl = 'https://images.unsplash.com/photo-1488646953014-85cb44e25828?auto=format&fit=crop&w=400&q=70';
  }
  return 'https://images.weserv.nl/?url=${Uri.encodeComponent(rawUrl)}';
}
